    var key = params[0];
    params.splice(0, 1);
    if('escapeHtml' in hash && hash.escapeHtml)
	{
		key = CommonUtil.escapeHTML(key);
	}
	let value = key;
    if('isSafe' in hash && !hash.isSafe)
  	{
  		value = I18NUtil.translate(key, params);
  	} else {
		value = Ember.String.htmlSafe(I18NUtil.translate(key, params));
	}
	if ('validate' in hash && hash.validate) {	// Will return boolean value of whether the i18n value present or not
