import Ember from 'ember';
import CommonUtil from '../utils/ads-common-util';
import iconUtil from '../utils/ads-icon-util';

/*
1. The usage {{fw-img sourcePath}} or (fw-img sourcePath).
Example: {{ads-i18n "user_consent_service_text" (fw-img "images/zoho-logo.png") }}
In the example above, the user_consent_service_text=<img src={0}> Corp.
*/

//2. The usage {{fw-img src="imagePath" class="classNames" height="10" width="10"}} forms and returns the entire HTML image tag.

export default Ember.Helper.extend({

    compute(params,namedArgs) {
        let sourcePath = params[0] || namedArgs.src;
        /*
        A custom method can be implemented on the product side, such as in the application's controller, to modify the 'src' attribute of an image.
        This can be used, for example, to convert a relative URL to an absolute URL.
        */
        if (CommonUtil.hasCustomImgPath) {
            sourcePath = CommonUtil.getCustomImgPath(sourcePath);
        }
        if (params[0] !== undefined){
            return sourcePath;
        }
        if(namedArgs.isBase64){
            sourcePath = "data:image/png;base64,"+namedArgs.src;
        }
        var args = {
            src: sourcePath
        };
        if(namedArgs.icon){
            if(namedArgs.iconTypeData){
                let data = namedArgs.iconTypeData;
                let iconAttrs = iconUtil.getProperties(data.module, data.category, namedArgs.icon);
                if(iconAttrs){
                    args = Ember.$.extend(true, {}, args, iconAttrs);
                }
            } else {
                args.class = namedArgs.icon;
            }
            delete namedArgs.icon;
        }
        //forms and returns the entire HTML Image tag.
        const cloneNamedArgs = Ember.$.extend(true, {}, namedArgs, args)
        const imageAttributes = Object.keys(cloneNamedArgs).map((key) => `${key}='${cloneNamedArgs[key]}'`).join(' ');
        const imageElement = `<img ${imageAttributes} >`
        return Ember.String.htmlSafe(imageElement);

    }
});
