import Ember from 'ember';
import CommonUtil from '../utils/ads-common-util';
import AJAXUtil from '../utils/ads-ajax-util';
import StatusUtil from "../utils/ads-status-util";
import I18NUtil from "../utils/i18n-util";

export default Ember.Component.extend({

    tagName: 'span',
    classNameBindings: ['data.TRUNCATE_TITLE:fw-w-inherit','data.TRUNCATE_TITLE:fw-text-ellipsis', 'data.ELEMENT_CLASS'], //No I18N
    action:"",
    searchNoData: false,
    showDropdown: false,
    openDropdownMenu: false,
    showClearSearch: false,
    NO_DATA_FOUND_TEXT: "",
    tt_container: "body",
    clickListener:null,

    onInit: function() {
        if(this.data === undefined) { // Load data from hash if ads-dropdown is used as additional component in ads-table (initializers/ads-component-attrs won't get triggered on init hook)
            this.loadADSAttrsHash();
        }

        var self = this;
        if(this.data.HANDLE_DYNAMIC_DATA){
            if(!this.data.DROPDOWN_MORE_LINK){
                Ember.set(this.data,"SHOW_DROPDOWN_MORE_LINK",false);
                Ember.set(this.data,"DROPDOWN_MORE_LINK",{
					"WITH_ICON":false,
					"TEXT": I18NUtil.translate('ads.common.text.show_more')
				});
            }
            this.getDropdownContent("",0);
        }
        if(!this.data.INIT_DATA_NOT_NEEDED){
            this.set("data",JSON.parse(JSON.stringify(this.data)));
        }
        if(this.data.CUSTOM_NO_DATA_FOUND_TEXT){
            this.set("NO_DATA_FOUND_TEXT",this.data.CUSTOM_NO_DATA_FOUND_TEXT);
        }else{
            this.set("NO_DATA_FOUND_TEXT",I18NUtil.translate("ads.common.text.no_data_found"));
        }
        this.send("clearSearch");
        if(this.get("data.TOOLTIP_CONTAINER")){
            this.set("tt_container",this.get("data.TOOLTIP_CONTAINER"));
        }

        if(this.data.INITIAL_SEARCH_VALUE && this.data.INITIAL_SEARCH_VALUE.length > 0){
            this.set("showClearSearch",true);
        }
        this.clickListener=Ember.run.bind(this,this.onClick);
        this.scrollListener = Ember.run.bind(this, this.onScrollAction);
    }.on("init"),

    duringRender:function(){
        var self = this;
        CommonUtil.renderScrollBar();
        this.renderTT();
        Ember.$("body").on('click',this.clickListener);
        Ember.$(window).scroll(this.scrollListener);
    }.on('didRender'),

    loadADSAttrsHash() {
        if (this.get('attrsHash') !== undefined && typeof this.get('attrsHash') === "object") {
            let hash = this.get('attrsHash');
            var keys = [];
            for (var i in hash) {
              if (hash.hasOwnProperty(i)) {
                keys.push(i);
              }
            }
            keys.forEach(key => {
              this.set(key, hash[key]);
            });
          }
    },

    onClick:function(e){
        if(this.data && !Ember.$(e.target).parents().hasClass("ads-dropdown ads-dropdown-"+this.data.ID) && !Ember.$(e.target).hasClass("ads-dropdown ads-dropdown-"+this.data.ID)) {
            this.set("showDropdown",false);
            Ember.set(this.data,"OPEN_DROPDOWN_ON_INIT",false);
            this.send("closeDropdown");
            Ember.$("#"+this.data.ID).removeClass("open");
        }
    },

    onScrollAction(){
        if(this.get("showDropdown")){
            this.send("closeDropdown");
        }
    },

    onDestroying:function(){
        this.send("closeDropdown");
        if(this.clickListener) {
            Ember.$("body").off("click",this.clickListener);
        }
        Ember.$(window).off('scroll',this.scrollListener);
        Ember.$("#"+this.get("elementId")+" > div").tooltip("destroy");
        Ember.$("#"+this.get("elementId")+" .showtt").tooltip("destroy");
    }.on('willDestroyElement'),

    dropdownOpenListener: function(){
        if(!this.showDropdown){
            if(this.data.SEARCH){
                this.send("clearSearch");
